const error = $input.first().json;
return [{
  json: {
    workflow_id: error.execution?.workflowId || 'unknown',
    execution_id: error.execution?.id || 'unknown',
    mode: error.execution?.mode || 'unknown',
    status: 'failed',
    error_message: error.execution?.error?.message || 'Unknown error',
    error_node: error.execution?.lastNodeExecuted || 'unknown',
    timestamp: new Date().toISOString(),
    source_platform: 'n8n',
    artifact_type: 'error_log',
    details: JSON.stringify({
      workflow_name: error.workflow?.name,
      retry_count: error.execution?.retryCount || 0,
      started_at: error.execution?.startedAt
    })
  }
}];

